package org.eclipse.rdf4j.sail.lmdb;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertNotNull;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.io.File;
import java.nio.file.Files;
import java.nio.file.Path;
import java.util.concurrent.TimeUnit;

import org.eclipse.rdf4j.common.iteration.CloseableIteration;
import org.eclipse.rdf4j.model.IRI;
import org.eclipse.rdf4j.model.Statement;
import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.sail.NotifyingSailConnection;
import org.eclipse.rdf4j.sail.lmdb.config.LmdbStoreConfig;
import org.eclipse.rdf4j.sail.lmdb.estimation.QuadProbe;
import org.eclipse.rdf4j.sail.lmdb.estimation.QuadSnapshotIdentity;
import org.eclipse.rdf4j.sail.lmdb.estimation.QuadValueHash;
import org.eclipse.rdf4j.sail.lmdb.sketch.SketchBasedJoinEstimator;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

class LmdbSailStoreEstimatorPersistenceTest {

	private static final SimpleValueFactory VF = SimpleValueFactory.getInstance();
	private static final IRI PREDICATE = VF.createIRI("urn:persistence:predicate");

	@Test
	void versionEightSnapshotRestartsWithStableIdentity(@TempDir File dataDir) throws Exception {
		QuadSnapshotIdentity writtenIdentity;
		LmdbStore writer = open(dataDir);
		try {
			addRows(writer, 3);
			assertTrue(writer.forceFlushSketchEstimator());
			SketchBasedJoinEstimator estimator = writer.getBackingStore().getSketchBasedJoinEstimator();
			assertEquals(3.0d, predicateRows(estimator));
			writtenIdentity = estimator.quadSnapshotIdentity();
		} finally {
			writer.shutDown();
		}

		Path snapshot = snapshot(dataDir);
		assertTrue(Files.isRegularFile(snapshot));

		LmdbStore reader = open(dataDir);
		try {
			assertTrue(reader.awaitSketchesReady(10, TimeUnit.SECONDS));
			SketchBasedJoinEstimator estimator = reader.getBackingStore().getSketchBasedJoinEstimator();
			assertEquals(writtenIdentity.storeIdHigh(), estimator.quadSnapshotIdentity().storeIdHigh());
			assertEquals(writtenIdentity.storeIdLow(), estimator.quadSnapshotIdentity().storeIdLow());
			assertEquals(3.0d, predicateRows(estimator));
			assertEquals(3L, exactStatementCount(reader));
		} finally {
			reader.shutDown();
		}
	}

	@Test
	void corruptPayloadRebuildsFromLmdbWithoutChangingResults(@TempDir File dataDir) throws Exception {
		QuadSnapshotIdentity writtenIdentity;
		LmdbStore writer = open(dataDir);
		try {
			addRows(writer, 4);
			assertTrue(writer.forceFlushSketchEstimator());
			writtenIdentity = writer.getBackingStore().getSketchBasedJoinEstimator().quadSnapshotIdentity();
		} finally {
			writer.shutDown();
		}

		Path snapshot = snapshot(dataDir);
		byte[] bytes = Files.readAllBytes(snapshot);
		bytes[bytes.length - Long.BYTES - 1] ^= 0x5a;
		Files.write(snapshot, bytes);

		LmdbStore reader = open(dataDir);
		try {
			assertTrue(reader.forceFlushSketchEstimator());
			SketchBasedJoinEstimator estimator = reader.getBackingStore().getSketchBasedJoinEstimator();
			assertNotNull(estimator);
			assertEquals(writtenIdentity.storeIdHigh(), estimator.quadSnapshotIdentity().storeIdHigh());
			assertEquals(writtenIdentity.storeIdLow(), estimator.quadSnapshotIdentity().storeIdLow());
			assertEquals(4.0d, predicateRows(estimator));
			assertEquals(4L, exactStatementCount(reader));
		} finally {
			reader.shutDown();
		}
	}

	private static LmdbStore open(File dataDir) {
		LmdbStore store = new LmdbStore(dataDir, new LmdbStoreConfig("spoc")
				.setSketchEstimatorEnabled(true)
				.setSketchEstimatorMemoryBudgetBytes(4L * 1024L * 1024L));
		store.init();
		return store;
	}

	private static void addRows(LmdbStore store, int count) {
		try (NotifyingSailConnection connection = store.getConnection()) {
			connection.begin();
			for (int index = 0; index < count; index++) {
				connection.addStatement(VF.createIRI("urn:persistence:s" + index), PREDICATE,
						VF.createLiteral(index));
			}
			connection.commit();
		}
	}

	private static long exactStatementCount(LmdbStore store) {
		long count = 0L;
		try (NotifyingSailConnection connection = store.getConnection();
				CloseableIteration<? extends Statement> statements = connection.getStatements(null, null, null, false)) {
			while (statements.hasNext()) {
				statements.next();
				count++;
			}
		}
		return count;
	}

	private static double predicateRows(SketchBasedJoinEstimator estimator) {
		QuadProbe probe = new QuadProbe(QuadProbe.PREDICATE, QuadProbe.OBJECT, 0L,
				QuadValueHash.hash(PREDICATE), 0L, 0L, estimator.quadSnapshotIdentity());
		return estimator.synopsisService().probe(probe).rows().estimate();
	}

	private static Path snapshot(File dataDir) {
		return dataDir.toPath().resolve("join-estimator.rjes/synopsis-v8.bin");
	}
}
